  ('elementary-8b44517b-moex-00386', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於故意與過失，下列敘述何者正確？', '["行為人對於構成犯罪之事實，雖預見其能發生而確信其不發生者，以故意論", "行為人對於構成犯罪之事實，預見其發生而其發生並不違背其本意者，以過失論", "故意可分為有認識之故意與無認識之故意", "故意可分為直接故意與間接故意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
